public sealed class ConstructionWorkCoordinatorV3
{
    private readonly ConstructionSessionV3 _construction;private readonly ResourceSessionV3 _resources;private readonly StockpileSessionV3 _stockpiles;private readonly MercenaryWorkSessionV3 _work;private readonly MercenaryControlSessionV3 _control;private readonly MercenarySessionV3 _mercenaries;private readonly IMercenaryNavigationWorldQueryV3 _query;private readonly string _localPlayerId;private readonly string _localCompanyId;private readonly Rect2I _worldBounds;private readonly bool _emitLogs;private readonly Dictionary<string,ConstructionJobV3> _jobs=new(StringComparer.Ordinal);private Func<string,float>? _workMultiplier;private long _revision;
    public event Action? Changed;public event Action? ResourcesChanged;public int ActiveJobCount=>_jobs.Count;public int LastSupplyTripCount{get;private set;}public string LastSupplyWorkerId{get;private set;}="";public string LastConstructionWorkerId{get;private set;}="";
    public ConstructionWorkCoordinatorV3(ConstructionSessionV3 construction,ResourceSessionV3 resources,StockpileSessionV3 stockpiles,MercenaryWorkSessionV3 work,MercenaryControlSessionV3 control,MercenarySessionV3 mercenaries,IMercenaryNavigationWorldQueryV3 query,WorldManagerV2 manager):this(construction,resources,stockpiles,work,control,mercenaries,query,manager.LocalPlayerId,manager.LocalCompanyId,manager.WorldBounds,true){}
    public ConstructionWorkCoordinatorV3(ConstructionSessionV3 construction,ResourceSessionV3 resources,StockpileSessionV3 stockpiles,MercenaryWorkSessionV3 work,MercenaryControlSessionV3 control,MercenarySessionV3 mercenaries,IMercenaryNavigationWorldQueryV3 query,string localPlayerId,string localCompanyId,Rect2I worldBounds,bool emitLogs=false){_construction=construction;_resources=resources;_stockpiles=stockpiles;_work=work;_control=control;_mercenaries=mercenaries;_query=query;_localPlayerId=localPlayerId;_localCompanyId=localCompanyId;_worldBounds=worldBounds;_emitLogs=emitLogs;}
    public void AttachWorkMultiplier(Func<string,float> resolver)=>_workMultiplier=resolver;
    public bool TryIssue(string blueprintId,IReadOnlyList<string> selected,out string reason){if(!_construction.Blueprints.TryGet(blueprintId,out var bp)||bp==null||bp.CompanyId!=_localCompanyId){reason="InvalidBlueprint";return false;}if(_construction.Reservations.IsReserved(blueprintId)){reason="BlueprintReserved";return false;}return bp.MaterialBuffer.IsComplete?TryBuild(bp,selected,out reason):TrySupply(bp,selected,out reason);}
    public bool CancelForDirectMove(string mercenaryId){bool cancelled=false;foreach(var job in _jobs.Values.Where(x=>x.MercenaryId==mercenaryId).ToList()){Fail(job,"CancelledByDirectMove");cancelled=true;}return cancelled;}
    public bool TryGetHudSnapshot(string mercenaryId,out ConstructionWorkHudSnapshotV3 snapshot)
    {foreach(var job in _jobs.Values)if(job.MercenaryId==mercenaryId&&_construction.Blueprints.TryGet(job.BlueprintId,out var bp)&&bp!=null){snapshot=new(job.Id,job.BlueprintId,job.Supply,job.Phase.ToString(),bp.AnchorCell,bp.ConstructionProgressSeconds,job.RequiredSeconds,job.CompletedTrips);return true;}snapshot=default;return false;}
    private bool TrySupply(ConstructionBlueprintStateV3 bp,IReadOnlyList<string> selected,out string reason){ResourceTypeV3 type=bp.MaterialBuffer.GetMissingAmount(ResourceTypeV3.Wood)>0?ResourceTypeV3.Wood:ResourceTypeV3.Stone;int missing=bp.MaterialBuffer.GetMissingAmount(type);List<GroundResourceStackV3> sources=GetAvailableSources(bp.CompanyId,type);if(sources.Sum(x=>x.Amount)<missing){reason="InsufficientStoredMaterials";return false;}GroundResourceStackV3 source=sources[0];if(!SelectWorker(selected,source.Cell,true,out string worker,out var profile,out reason))return false;_work.NotifyExternalWorkSupersede(worker);string id=WorkRequestIdFactoryV3.Create();long rev=++_revision;var job=new ConstructionJobV3{Id=id,BlueprintId=bp.BlueprintId,MercenaryId=worker,Supply=true,Revision=rev,Phase=ConstructionJobPhaseV3.MoveToSource,MaterialType=type,MaxCarryUnits=HaulingWorkCalculatorV3.GetMaxCarryUnits(profile!)};if(!_construction.Reservations.TryReserve(new(bp.BlueprintId,id,worker,bp.CompanyId,ConstructionReservationPurposeV3.MaterialDelivery,DateTime.UtcNow,rev),out reason))return false;_jobs.Add(id,job);LastSupplyWorkerId=worker;if(!PlanNextSource(job,bp,out reason)){Fail(job,reason);return false;}if(_emitLogs)GD.Print($"[ConstructionV3] Supply started blueprint={bp.BlueprintId} worker={worker} amount={missing}");reason=string.Empty;return true;}
    private bool TryBuild(ConstructionBlueprintStateV3 bp,IReadOnlyList<string> selected,out string reason){if(!SelectWorker(selected,bp.AnchorCell,false,out string worker,out var profile,out reason))return false;var approaches=ConstructionApproachCellServiceV3.GetCandidates(bp.OccupiedCells,_mercenaries.Registry.TryGetState(worker,out var st)&&st!=null?st.CurrentCell:bp.AnchorCell,_query);if(approaches.Count==0){reason="NoApproachCells";return false;}_work.NotifyExternalWorkSupersede(worker);string id=WorkRequestIdFactoryV3.Create();long rev=++_revision;var definition=_construction.Definitions.TryGetDefinition(bp.DefinitionId,out var d)?d:null;if(definition==null){reason="InvalidDefinition";return false;}var calc=ConstructionWorkCalculatorV3.Calculate(profile!,definition.BaseConstructionDurationSeconds);var job=new ConstructionJobV3{Id=id,BlueprintId=bp.BlueprintId,MercenaryId=worker,Supply=false,Revision=rev,Phase=ConstructionJobPhaseV3.MoveToBuild,ApproachCell=approaches[0],RequiredSeconds=calc.RequiredConstructionSeconds};if(!_construction.Reservations.TryReserve(new(bp.BlueprintId,id,worker,bp.CompanyId,ConstructionReservationPurposeV3.Construction,DateTime.UtcNow,rev),out reason))return false;_jobs.Add(id,job);LastConstructionWorkerId=worker;RequestMove(job,job.ApproachCell);if(_emitLogs)GD.Print($"[ConstructionV3] Construction started blueprint={bp.BlueprintId} worker={worker} seconds={job.RequiredSeconds:0.00}");reason=string.Empty;return true;}
    private List<GroundResourceStackV3> GetAvailableSources(string company,ResourceTypeV3 type)=>_resources.GroundStacks.GetAllStackIds().Select(id=>(_resources.GroundStacks.TryGet(id,out var s),s)).Where(x=>x.Item1&&x.s!=null&&x.s.ResourceType==type&&_resources.AmountReservations.GetAvailableAmount(x.s.ResourceStackId)>0&&_stockpiles.Zones.IsOwnedStockpileCell(company,x.s.Cell)&&!_work.SourceStackReservations.IsReserved(x.s.ResourceStackId)).Select(x=>x.s!).OrderByDescending(x=>_resources.AmountReservations.GetAvailableAmount(x.ResourceStackId)).ThenBy(x=>x.ResourceStackId,StringComparer.Ordinal).ToList();
    private bool PlanNextSource(ConstructionJobV3 job,ConstructionBlueprintStateV3 bp,out string reason){List<GroundResourceStackV3> sources=GetAvailableSources(bp.CompanyId,job.MaterialType);if(sources.Count==0){reason="NoStoredMaterials";return false;}GroundResourceStackV3 source=sources[0];job.SourceStackId=source.ResourceStackId;job.SourceCell=source.Cell;job.Amount=Math.Min(Math.Min(_resources.AmountReservations.GetAvailableAmount(source.ResourceStackId),bp.MaterialBuffer.GetMissingAmount(job.MaterialType)),job.MaxCarryUnits);if(job.Amount<1){reason="InvalidSupplyAmount";return false;}if(!_work.SourceStackReservations.TryReserve(new(source.ResourceStackId,job.Id,job.MercenaryId,bp.CompanyId,job.Amount,job.Revision,DateTime.UtcNow),out reason))return false;job.Phase=ConstructionJobPhaseV3.MoveToSource;RequestMove(job,source.Cell);return _jobs.ContainsKey(job.Id);}
    private bool SelectWorker(IReadOnlyList<string> selected,GlobalCellCoord target,bool hauling,out string worker,out MercenaryProfileV3? profile,out string reason){worker="";profile=null;var list=new List<(string Id,MercenaryProfileV3 P,float Score,float Dist,int Index)>();bool exhausted=false;for(int i=0;i<selected.Count;i++){if(!_work.CanStartFor(selected[i],WorkTypeV3.Construction,out _)){exhausted=true;continue;}if(_mercenaries.CanPlayerControlMercenary(_localPlayerId,selected[i])&&_mercenaries.Registry.TryGetMercenary(selected[i],out var p,out var s)&&p!=null&&s!=null){float score=hauling?HaulingWorkCalculatorV3.Calculate(p).HaulingScore:ConstructionWorkCalculatorV3.Calculate(p,6).ConstructionScore;list.Add((selected[i],p,score,MercenaryMovementCostPolicyV3.Octile(s.CurrentCell.Value,target.Value),i));}}var best=list.OrderByDescending(x=>x.Score).ThenBy(x=>x.Dist).ThenBy(x=>x.Index).ThenBy(x=>x.Id,StringComparer.Ordinal).FirstOrDefault();if(best.P==null){reason=exhausted?"TooExhausted":"NoEligibleWorker";return false;}worker=best.Id;profile=best.P;reason="";return true;}
    private void RequestMove(ConstructionJobV3 job,GlobalCellCoord destination){if(!_mercenaries.Registry.TryGetState(job.MercenaryId,out var state)||state==null){Fail(job,"WorkerRemoved");return;}_work.CancelForDirectMove(job.MercenaryId);_control.SupersedeDirectMovementForWork(job.MercenaryId);if(!_control.ExternalMovements.TryRequest(job.MercenaryId,state.CurrentCell,destination,MovementRequestSourceTypeV3.Work,job.Id,_control.SessionRevision,job.Revision,_control.Movements,out _,out string reason))Fail(job,reason);}
    public bool TryHandleMovementResult(MercenaryMovementResultV3 result){if(!_jobs.TryGetValue(result.Request.SourceId,out var job)||job.Revision!=result.Request.SourceRevision)return false;if(!result.Succeeded){Fail(job,"MovementFailed");return true;}if(job.Phase==ConstructionJobPhaseV3.MoveToSource){CommitPickup(job);return true;}if(job.Phase==ConstructionJobPhaseV3.MoveToBlueprint){job.Phase=ConstructionJobPhaseV3.Deliver;CommitDelivery(job);return true;}if(job.Phase==ConstructionJobPhaseV3.MoveToBuild){if(_construction.Blueprints.TryGet(job.BlueprintId,out var bp)&&bp!=null&&bp.TryBeginConstruction(out _)){job.Phase=ConstructionJobPhaseV3.Build;_mercenaries.Registry.TryGetState(job.MercenaryId,out var s);s?.TrySetActivityState(MercenaryActivityStateV3.Working,out _);Changed?.Invoke();}else Fail(job,"InvalidConstructionState");return true;}return true;}
    private void CommitPickup(ConstructionJobV3 job){if(!_resources.GroundStacks.TryTakeAmount(job.SourceStackId,job.Amount,out int taken,out _,out _,out string reason)){Fail(job,"PickupFailed");return;}if(!_work.Carries.TryBeginCarry(job.MercenaryId,job.Id,job.MaterialType,taken,job.SourceStackId,job.Revision,job.MaxCarryUnits,out _,out reason)){_resources.GroundStacks.TryAddOrMerge(job.MaterialType,taken,job.SourceCell,out _,out _,out _);Fail(job,"PickupFailed");return;}_work.SourceStackReservations.TryRelease(job.SourceStackId,job.Id);ResourcesChanged?.Invoke();if(!_construction.Blueprints.TryGet(job.BlueprintId,out var bp)||bp==null||!_mercenaries.Registry.TryGetState(job.MercenaryId,out var state)||state==null){Fail(job,"InvalidBlueprint");return;}var approaches=ConstructionApproachCellServiceV3.GetCandidates(bp.OccupiedCells,state.CurrentCell,_query);if(approaches.Count==0){Fail(job,"NoApproachCells");return;}job.ApproachCell=approaches[0];job.Phase=ConstructionJobPhaseV3.MoveToBlueprint;RequestMove(job,job.ApproachCell);Changed?.Invoke();}
    private void CommitDelivery(ConstructionJobV3 job){if(!_construction.Blueprints.TryGet(job.BlueprintId,out var bp)||bp==null||!_work.Carries.TryGetCarry(job.MercenaryId,out var carry)||carry==null||!bp.MaterialBuffer.CanAccept(carry.ResourceType,carry.Amount)){Fail(job,"DropFailed");return;}if(!bp.MaterialBuffer.TryDeliver(carry.ResourceType,carry.Amount,out _)||!_work.Carries.TryClearCarry(job.MercenaryId,job.Id,out _)){Fail(job,"DropFailed");return;}job.CompletedTrips++;bp.RefreshMaterialStatus();Changed?.Invoke();if(!bp.MaterialBuffer.IsComplete){if(!PlanNextSource(job,bp,out string reason))Fail(job,reason);return;}LastSupplyTripCount=job.CompletedTrips;Finish(job);if(_emitLogs)GD.Print($"[ConstructionV3] Supply completed blueprint={bp.BlueprintId} trips={job.CompletedTrips} ready=true");}
    public void Tick(float delta){foreach(var job in _jobs.Values.ToList()){if(job.Phase is not (ConstructionJobPhaseV3.Build or ConstructionJobPhaseV3.WaitingClear))continue;if(!_construction.Blueprints.TryGet(job.BlueprintId,out var bp)||bp==null){Fail(job,"InvalidBlueprint");continue;}if(job.Phase==ConstructionJobPhaseV3.Build)bp.AddProgress(delta*Math.Clamp(_workMultiplier?.Invoke(job.MercenaryId)??1f,.1f,2f));if(bp.ConstructionProgressSeconds<job.RequiredSeconds){Changed?.Invoke();continue;}if(!FootprintClear(bp,job.MercenaryId)){bp.SetWaitingForClear();job.Phase=ConstructionJobPhaseV3.WaitingClear;Changed?.Invoke();continue;}Complete(job,bp);}}
    private bool FootprintClear(ConstructionBlueprintStateV3 bp,string builder){HashSet<Vector2I> cells=new(bp.OccupiedCells.Select(x=>x.Value));foreach(string id in _mercenaries.Registry.GetAllMercenaryIds())if(_mercenaries.Registry.TryGetState(id,out var s)&&s!=null&&cells.Contains(s.CurrentCell.Value))return false;foreach(string id in _control.Movements.GetActiveIds())if(_control.Movements.TryGet(id,out var m)&&m!=null&&cells.Contains(m.ToCell.Value))return false;return true;}
    private void Complete(ConstructionJobV3 job,ConstructionBlueprintStateV3 bp){if(!_construction.Definitions.TryGetDefinition(bp.DefinitionId,out var d)||d==null){Fail(job,"InvalidDefinition");return;}var structure=new StructureStateV3(StructureIdFactoryV3.Create(),bp.CompanyId,bp.DefinitionId,bp.AnchorCell,bp.Orientation,bp.OccupiedCells,bp.MaterialBuffer.GetDeliveredMaterialsSnapshot(),d.BlocksMovement,DateTime.UtcNow);if(!_construction.Structures.TryRegister(structure,_construction.Blueprints,_worldBounds,out string reason,bp.BlueprintId)){Fail(job,reason);return;}if(!_construction.Blueprints.TryRemove(bp.BlueprintId,out _)){_construction.Structures.TryRemove(structure.StructureId,out _);Fail(job,"CompletionFailed");return;}bp.MarkCompleted();_construction.Diagnostics.CompletedStructureCount++;Finish(job);if(_emitLogs)GD.Print($"[ConstructionV3] Structure completed id={structure.StructureId} definition={structure.DefinitionId}");}
    public bool TryCancelBlueprint(string id,out string reason){if(!_construction.Blueprints.TryGet(id,out var bp)||bp==null||bp.CompanyId!=_localCompanyId){reason="InvalidBlueprint";return false;}foreach(var job in _jobs.Values.Where(x=>x.BlueprintId==id).ToList())Fail(job,"CancelledByBlueprintRemoval");var materials=bp.MaterialBuffer.GetDeliveredMaterialsSnapshot();if(!_construction.Blueprints.TryRemove(id,out _)){reason="BlueprintRemovalFailed";return false;}foreach(var m in materials)_resources.GroundStacks.TryAddOrMerge(m.ResourceType,m.RequiredAmount,bp.AnchorCell,out _,out _,out _);bp.MarkCancelled();_construction.Diagnostics.CancelledBlueprintCount++;ResourcesChanged?.Invoke();Changed?.Invoke();reason="";return true;}
    private void Finish(ConstructionJobV3 job){_construction.Reservations.ReleaseByWorkRequest(job.Id);_work.SourceStackReservations.ReleaseByWorkRequest(job.Id);_jobs.Remove(job.Id);_mercenaries.Registry.TryGetState(job.MercenaryId,out var state);state?.TrySetActivityState(MercenaryActivityStateV3.Idle,out _);Changed?.Invoke();}
    private void Fail(ConstructionJobV3 job,string reason){if(_work.Carries.TryGetCarry(job.MercenaryId,out var carry)&&carry?.WorkRequestId==job.Id&&_mercenaries.Registry.TryGetState(job.MercenaryId,out var state)&&state!=null){_work.Carries.TryDropCarryAtCell(job.MercenaryId,job.Id,state.CurrentCell,_resources.GroundStacks,out _,out _);ResourcesChanged?.Invoke();}_control.ExternalMovements.Cancel(job.MercenaryId,reason,_control.Movements);_construction.Diagnostics.LastFailureReason=reason;Finish(job);}
}
